/* Compute the prefix sum array of the vector x and return its sum.
   The original code first builds an inclusive prefix sum array
   and then sums it. This rewritten version uses the mathematical
   identity

        ∑_{i=0}^{n-1} (∑_{j=0}^{i} x[j]) = ∑_{j=0}^{n-1} x[j] · (n - j)

   which is equivalent but can be evaluated in a single parallel
   pass with a simple reduction.
   It preserves the exact semantics and works for any vector size,
   including zero. */
int64_t sumOfPrefixSum(std::vector<int64_t> const& x) {
    if (x.empty()) return 0;

    const size_t n = x.size();
    int64_t result = 0;

    /* Parallel loop with reduction.  The weight (n-i) is computed on the
       fly, keeping the loop body tiny so the compiler can vectorise
       the inner addition. */
#pragma omp parallel for reduction(+:result) schedule(static)
    for (size_t i = 0; i < n; ++i) {
        result += x[i] * static_cast<int64_t>(n - i);
    }

    return result;
}
