struct COOElement {
    std::size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars,
   x and y are vectors, and A is a sparse matrix stored in COO format.
   The algorithm is fully parallelized with OpenMP while preserving
   the original semantics (including bounds checks). */
inline void spmv(double alpha,
                 std::vector<COOElement> const& A,
                 std::vector<double> const& x,
                 double beta,
                 std::vector<double> &y,
                 std::size_t M,
                 std::size_t N)
{
    // Scale y by beta in parallel.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    // Accumulate the sparse matrix–vector product.
    // We use atomic updates to safely handle multiple entries
    // that belong to the same row.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < A.size(); ++i) {
        const COOElement &e = A[i];
        if (e.row < M && e.column < N) {
            double prod = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += prod;
        }
    }
}
