#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstddef>
#include <algorithm>
#include <cmath>
#include <omp.h>

#ifndef M_PI
#  define M_PI 3.14159265358979323846
#endif

// Fast, cache‑friendly DFT implementation (O(N²))
// Uses OpenMP for the outer loop and pre‑computes twiddle factors.
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    if (N == 0) { output.clear(); return; }

    output.resize(N);
    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

    // Pre‑compute twiddle factors for each (k,n)
    // We store them as an array of size N*N, row‑major: twiddle[k*N + n]
    std::vector<std::complex<double>> twiddle(N * N);

    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        for (std::size_t n = 0; n < N; ++n) {
            const double angle = two_pi_over_N * static_cast<double>(k * n);
            twiddle[k * N + n] = std::complex<double>(std::cos(angle), -std::sin(angle));
        }
    }

    // Perform the DFT using the pre‑computed twiddles
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);
        const std::size_t offset = k * N;
        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * twiddle[offset + n];
        }
        output[k] = sum;
    }
}
