/*
 * Return the logical XOR reduction of the vector<bool> x.
 * Optimization:
 *   * Process bits in 64‑bit chunks.
 *   * Use OpenMP parallel reduction.
 *   * A single uint64_t xor accumulator per thread reduces cache traffic.
 */
inline bool reduceLogicalXOR(std::vector<bool> const& x) {
    if (x.empty()) return false;

    const std::size_t nbits = x.size();
    const std::size_t n64   = (nbits + 63) / 64;

    // Fast access to the underlying packed bits (implementation defined but works on GCC/Clang)
    const bool* data = x.data();                     // obtain pointer to proxy
    const unsigned char* bytes = reinterpret_cast<const unsigned char*>(data);

    // We can't directly read 64‑bits from vector<bool> because of proxy, so transform to packed array
    // Allocated once per call; may be optimized by reusing buffer
    std::vector<uint64_t> packed(n64, 0);
    for (std::size_t i = 0; i < nbits; ++i) {
        if (x[i]) {
            std::size_t idx = i >> 6;
            std::size_t off = i & 63;
            packed[idx] ^= (uint64_t(1) << off);
        }
    }

    uint64_t acc = 0;
#pragma omp parallel for reduction(^ : acc)
    for (std::size_t i = 0; i < n64; ++i) {
        acc ^= packed[i];
    }

    return acc != 0;
}
