#pragma once
#include <vector>

struct Element
{
    std::size_t index;
    double        value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
 * `z` is assumed to be pre‑allocated with a size at least
 * `max(x.back().index, y.back().index)+1`. */
inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double> &z)
{
    const std::size_t xn = x.size(), yn = y.size();
    std::size_t xi = 0, yi = 0;

    // Main merge loop
    while (xi < xn && yi < yn)
    {
        const std::size_t ix = x[xi].index;
        const std::size_t iy = y[yi].index;

        if (ix < iy)          // only x
        {
            z[ix] += alpha * x[xi].value;
            ++xi;
        }
        else if (ix > iy)     // only y
        {
            z[iy] += y[yi].value;
            ++yi;
        }
        else                  // both
        {
            z[ix] += alpha * x[xi].value + y[yi].value;
            ++xi;
            ++yi;
        }
    }

    // Remaining tail of x
    while (xi < xn)
    {
        const std::size_t ix = x[xi].index;
        z[ix] += alpha * x[xi].value;
        ++xi;
    }

    // Remaining tail of y
    while (yi < yn)
    {
        const std::size_t iy = y[yi].index;
        z[iy] += y[yi].value;
        ++yi;
    }
}
