#pragma once
#include <vector>
#include <limits>

/* Return the length of the shortest path from source to dest in the
 * undirected graph defined by the adjacency matrix A.
 * A is an NxN adjacency matrix stored in row‑major order.
 * The graph is assumed to be connected and undirected.
 */
int shortestPathLength(const std::vector<int> &A, size_t N, int source, int dest) {
    // Use an integer array to store distances; -1 signifies unvisited.
    std::vector<int> dist(N, -1);
    // Simple ring buffer queue implemented on a fixed array.
    std::vector<int> q(N);
    int head = 0, tail = 0;

    dist[source] = 0;
    q[tail++] = source;

    while (head != tail) {
        int cur = q[head++];
        if (head == N) head = 0;          // wrap around

        int curDist = dist[cur];
        // Scan all possible neighbors (row in adjacency matrix)
        int base = static_cast<int>(cur) * static_cast<int>(N);
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (A[base + i] && dist[i] == -1) {
                dist[i] = curDist + 1;
                if (i == dest) return dist[i];
                q[tail++] = i;
                if (tail == N) tail = 0;  // wrap around
            }
        }
    }
    return std::numeric_limits<int>::max();  // unreachable (should not happen)
}
