struct Point {
   double x, y;
};

/* Count the number of cartesian points in each quadrant. The vector points contains a
   list of `Point` objects. Store the counts in `bins`.
   Example:
   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9}, {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
   output: [3, 1, 0, 2] */
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4> &bins) {
   // Zero the output array
   bins[0] = bins[1] = bins[2] = bins[3] = 0;

   // Per‑thread local counters to avoid contention
   const size_t nThreads = 8;                     // known number of logical cores
   std::array<std::array<size_t, 4>, nThreads> local;
   for (auto & l : local) l = {0, 0, 0, 0};

   #pragma omp parallel
   {
      const int tid = omp_get_thread_num();
      const size_t chunk = points.size() / nThreads;
      const size_t start = tid * chunk;
      const size_t end   = (tid == nThreads-1) ? points.size() : start + chunk;

      auto & b = local[tid];
      for (size_t i = start; i < end; ++i) {
         _Bool xPos = points[i].x >= 0.0;
         _Bool yPos = points[i].y >= 0.0;
         // Quadrant index is (x<0)*2 + (y<0)*1
