/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:
   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
   This implementation uses OpenMP to parallelise the histogram accumulation
   while avoiding false‑sharing and unnecessary atomics.
*/
void pixelCounts(std::vector<int> const& image, std::array<std::size_t, 256> &bins) {
    constexpr std::size_t BINS = 256;
    const std::size_t n = image.size();

#if _OPENMP >= 200805
    /* Determine the number of worker threads.  The number of threads may be
       smaller than the target hardware threads; OpenMP will decide based on the
       environment. */
    const int nthreads = omp_get_max_threads();

    /* Thread‑private histograms – each thread creates an array of BINS
       counters.  Allocating on the stack would risk overflow; allocate a
       single large buffer and slice it per thread. */
    std::vector<std::size_t> local;
    local.resize(nthreads * BINS, 0);

#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::size_t *const thread_bins = local.data() + static_cast<std::size_t>(tid) * BINS;

        /* Use a simple chunked loop to balance work. */
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            thread_bins[static_cast<std::size_t>(image[i])]++;
        }
    }

    /* Combine the per‑thread histograms into the final result. */
    for (std::size_t t = 0; t < nthreads; ++t) {
        const std::size_t *const src = local.data() + t * BINS;
        for (std::size_t b = 0; b < BINS; ++b) {
            bins[b] += src[b];
        }
    }
#else
    /* If OpenMP is not available, fall back to a serial implementation. */
#pragma omp parallel for schedule(static) reduction(+:bins[:BINS])
    for (std::size_t i = 0; i < n; ++i) {
        bins[static_cast<std::size_t>(image[i])]++;
    }
#endif
}
