double smallestArea(std::vector<Point> const& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallelise the outermost loop; each thread works on a distinct i range
    #pragma omp parallel for schedule(dynamic)
    for (std::size_t i = 0; i < n - 2; ++i) {
        double localMin = minArea;
        for (std::size_t j = i + 1; j < n - 1; ++j) {
            for (std::size_t k = j + 1; k < n; ++k) {
                // Cross‑product based area / 2
                double area = 0.5 * std::abs(
                    points[i].x * (points[j].y - points[k].y) +
                    points[j].x * (points[k].y - points[i].y) +
                    points[k].x * (points[i].y - points[j].y));
                if (area < localMin) localMin = area;
            }
        }
        // Reduce local minima across threads
        #pragma omp critical
        if (localMin < minArea) minArea = localMin;
    }
    return minArea;
}
