/* Return the distance between the closest two elements in the vector `x`.
   Example:
     input: [7, 3, 9, 12, 31, 1]
     output: 2
*/
inline double closestPair(std::vector<double> const& x)
{
    // The vector needs to have at least two elements
    if (x.size() < 2) {
        return 0.0;
    }

    // Work on a local copy to avoid modifying the caller's vector
    std::vector<double> sorted = x;
    std::sort(sorted.begin(), sorted.end());

    // The minimum distance in a sorted list is always found among adjacent pairs.
    double minDist = std::numeric_limits<double>::max();

    // Parallel reduction over adjacent pairs
    #pragma omp parallel for reduction(min:minDist)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(sorted.size()) - 1; ++i) {
        double d = std::fabs(sorted[i+1] - sorted[i]);
        if (d < minDist) {
            minDist = d;
        }
    }

    return minDist;
}
