```cpp
#pragma once
#include <vector>
#include <cstring>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* LU factorisation of a sparse matrix stored in COO format.
 * Result is written into L and U (row‑major dense formats).
 *
 * The implementation keeps the exact behaviour of the original
 * code while using a 1‑D dense representation and parallelising
 * independent work inside the outer loop.
 */
void luFactorize(const std::vector<COOElement> &A,
                 std::vector<double> &L,
                 std::vector<double> &U,
                 size_t N)
{
    /* dense representation of A – one 1‑D array is faster for cache
       access than a vector of vectors                               */
    std::vector<double> fullA(N * N, 0.0);
    for (const auto &el : A)
        fullA[el.row * N + el.column] = el.value;

    /* initialise L and U with zeros */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* outer loop is sequential – the algorithm is inherently
       sequential – but the inner j‑loop can be parallelised */
    for (size_t i = 0; i < N; ++i) {
        /* Parallelise work over all columns j for this row i */
#pragma omp parallel for schedule(static)
        for (size_t j = 0; j < N; ++j) {
            double val = fullA[i * N + j];

            if (j >= i) {                 // compute U[i][j]
                double sum = val;
                for (size_t k = 0; k < i; ++k)
                    sum -= L[i * N + k] * U[k * N + j];
                U[i * N + j] = sum;
            }

            if (i > j) {                  // compute L[i][j]
                double sum = val;
                for (size_t k = 0; k < j; ++k)
                    sum -= L[i * N + k] * U[k * N + j];
                /* U[j][j] is already computed in the same iteration */
                L[i * N + j] = sum / U[j * N + j];
            }
        }

        /* Diagonal of L is 1 (lower triangular unit) */
        L[i * N + i] = 1.0;
    }
}
