#pragma once
#include <vector>
#include <cstdint>
#include <cstddef>
#include <omp.h>

/*
 * Compute the prefix sum of the vector x into output.
 * Example:
 *   input:  [1, 7, 4, 6, 6, 2]
 *   output: [1, 8, 12, 18, 24, 26]
 *
 * The implementation performs a two‑pass parallel prefix sum
 * (one pass to compute local sub‑prefixes and block sums, the
 * other to add block offsets to each block), which gives good
 * performance on up to eight threads on modern x86‑64 CPUs.
 */
inline void prefixSum(const std::vector<int64_t> &x, std::vector<int64_t> &output)
{
    const size_t N = x.size();
    if (N == 0) return;

    // Ensure the output buffer is large enough.
    if (output.size() < N) output.resize(N);

    const int num_threads = omp_get_max_threads();
    const size_t block = (N + num_threads - 1) / num_threads;

    std::vector<int64_t> block_sum(num_threads, 0);

    // 1st pass: local prefix sums + block sums.
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const size_t start = tid * block;
        const size_t end   = std::min(start + block, N);

        if (start >= end) return;

        int64_t sum = 0;
        for (size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        block_sum[tid] = sum;
    }

    // 2nd pass: accumulate block sums and add to each block.
    int64_t offset = 0;
    for (int tid = 0; tid < num_threads; ++tid) {
        const size_t start = tid * block;
        const size_t end   = std::min(start + block, N);
        if (start >= end) continue;

        // Add the offset to the block.
        for (size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
        offset += block_sum[tid];
    }
}
