#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>
#include <unordered_map>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute Y = A * X.
 * A : sparse MxK matrix in COO format
 * X : sparse KxN matrix in COO format
 * Y : dense MxN matrix, row‑major
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    Y.assign(M * N, 0.0);

    // Build a small hash table grouping X by its row for better locality
    std::unordered_map<size_t, std::vector<COOElement>> xr;
    xr.reserve(X.size() * 2);
    for (auto const& e : X)
        xr[e.row].push_back(e);

    #pragma omp parallel
    {
        // Local buffer for atomic accumulation per thread
        std::vector<double> localY(M * N, 0.0);

        #pragma omp for schedule(static)
        for (size_t i = 0; i < A.size(); ++i) {
            const auto& a = A[i];
            auto it = xr.find(a.column);
            if (it == xr.end()) continue;
            const auto& vec = it->second;

            size_t base = a.row * N;
            for (auto const& x : vec) {
                double prod = a.value * x.value;
                localY[base + x.column] += prod;
            }
        }

        // Merge thread-local results back to Y
        #pragma omp critical
        {
            for (size_t idx = 0; idx < M * N; ++idx)
                Y[idx] += localY[idx];
        }
    }
}
