/*
 * Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.
 * Each element of `input` is averaged with its two neighbors and stored
 * in the corresponding element of `output`.  A missing neighbor (past
 * the input boundaries) is treated as zero.
 *
 * Example:
 *   input : [9, -6, -1,  2, 3]
 *   output: [ 1,  2/3, -5/3, 4/3, 5/3]
 */
inline void jacobi1D(const std::vector<double> &input, std::vector<double> &output) {
    const std::size_t n = input.size();

    /* ----- Handle trivial case ----- */
    if (n == 0) return;
    if (n == 1) {
        output[0] = input[0] / 3.0;
        return;
    }

    /* ----- Parallel loop ----- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        double left  = (i > 0)        ? input[i - 1] : 0.0;
        double right = (i + 1 < n)    ? input[i + 1] : 0.0;
        output[i] = (left + input[i] + right) / 3.0;
    }
}
