/*
 * Replace the i-th element of the vector x with the minimum value from
 * indices 0 through i.
 */
static inline void partialMinimums(std::vector<float> &x) {
    const std::size_t n = x.size();
    if (n < 2) return;                    // nothing to do for 0 or 1 element

    const int nthreads = omp_get_max_threads();
    std::vector<float> chunk_min(nthreads, std::numeric_limits<float>::max());

    /* 1. Local prefix‑min per chunk ------------------------------------- */
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t chunk_size = (n + nthreads - 1) / nthreads;
        const std::size_t start = tid * chunk_size;
        const std::size_t end   = std::min(start + chunk_size, n);

        if (start < end) {
            float curr = x[start];
            x[start] = curr;
            for (std::size_t i = start + 1; i < end; ++i) {
                curr = std::min(curr, x[i]);
                x[i] = curr;
            }
            chunk_min[tid] = curr;
        }
    }

    /* 2. Scaled prefix min of chunk minima --------------------------------*/
    float acc = std::numeric_limits<float>::max();
    for (int i = 0; i < nthreads; ++i) {
        float old = chunk_min[i];
        chunk_min[i] = std::min(acc, old);
        acc = chunk_min[i];
    }

    /* 3. Add global prefix of preceding chunks to each element ------------*/
#pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < n; ++idx) {
        const int tid = idx * nthreads / n;
        if (tid > 0) {
            const float prev_min = chunk_min[tid - 1];
            x[idx] = std::min(x[idx], prev_min);
        }
    }
}
