```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

/* 
   In-place radix‑2 decimation‑in‑time FFT
   The function writes the real and imaginary parts
   of the result into the caller provided vectors ‘r’ and ‘i’.
   The size of ‘x’ must be a power of two.
*/
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<double>& r,
                std::vector<double>& i)
{
    const size_t N = x.size();
    if (N == 0) return;

    // ensure output capacity
    if (r.size() < N) r.resize(N);
    if (i.size() < N) i.resize(N);

    // copy input into working buffer
    std::vector<std::complex<double>> a = x;

    /* ----------  Bit reversal ---------- */
    // precompute reversed indices
    std::vector<size_t> rev(N);
    size_t m = 0;
    for (size_t t = N; t > 1; t >>= 1) ++m;          // log2(N)
    for (size_t j = 0; j < N; ++j) {
        size_t rj = 0;
        size_t jj = j;
        for (size_t k = 0; k < m; ++k) {
            rj = (rj << 1) | (jj & 1);
            jj >>= 1;
        }
        rev[j] = rj;
    }
    // perform bit‑reversal swap
    for (size_t j = 0; j < N; ++j) {
        size_t jp = rev[j];
        if (jp > j) std::swap(a[j], a[jp]);
    }

    /* ----------  FFT stages ---------- */
    // pre‑compute twiddle factors
    std::vector<std::complex<double>> w(N/2);
    const double pi = std::acos(-1.0);
    for (size_t k = 0; k < N/2; ++k) {
        double theta = -2.0 * pi * static_cast<double>(k) / static_cast<double>(N);
        w[k] = std::complex<double>(std::cos(theta), std::sin(theta));
    }

    for (size_t s = 1; s <= m; ++s) {
        const size_t half = 1ULL << (s-1);
        const size_t full  = 1ULL << s;
        const size_t jump  = N >> s;

#pragma omp parallel for schedule(guided)
        for (size_t i = 0; i < N; i += full) {
            for (size_t j = 0; j < half; ++j) {
                std::complex<double> t = w[(j*jump) % (N/2)] * a[i + j + half];
                std::complex<double> u = a[i + j];
                a[i + j]         = u + t;
                a[i + j + half] = u - t;
            }
        }
    }

    /* ----------  Extract real/imag ---------- */
    for (size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
