```cpp
#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    /* 1. Allocate a flat NxN matrix and a copy of the RHS. */
    double *matrix = new double[N * N]();
    std::vector<double> b_copy = b;

    /* 2. Fill the matrix in parallel. */
#pragma omp parallel for schedule(static, 1024)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const COOElement &e = A[idx];
        matrix[e.row * N + e.column] = e.value;
    }

    x.assign(N, 0.0);

    /* 3. Gaussian elimination with partial pivoting. */
    for (size_t i = 0; i < N; ++i) {
        /* --- find pivot --- */
        double maxEl = std::abs(matrix[i * N + i]);
        size_t maxRow = i;
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxEl) {
                maxEl = val;
                maxRow = k;
            }
        }

        /* --- swap rows i and maxRow (entire row) --- */
        if (maxRow != i) {
            for (size_t k = i; k < N; ++k) {
                std::swap(matrix[maxRow * N + k], matrix[i * N + k]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* --- eliminate rows below --- */
        double diag = matrix[i * N + i];
        for (size_t k = i + 1; k < N; ++k) {
            double c = -matrix[k * N + i] / diag;
#pragma omp simd
            for (size_t j = i; j < N; ++j) {
                if (i == j) {
                    matrix[k * N + j] = 0.0;
                } else {
                    matrix[k * N + j] += c * matrix[i * N + j];
                }
            }
            b_copy[k] += c * b_copy[i];
        }
    }

    /* 4. Back substitution. */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i] / matrix[i * N + i];
        x[i] = sum;
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= matrix[k * N + i] * sum;
        }
    }

    delete[] matrix;
}
