#include <omp.h>

/* Compute z = alpha*x + y where x and y are vectors.
   The function assumes that x, y and z have the same size.
   Exact behavior is preserved while using OpenMP for parallel execution
   and a small unrolled loop for better SIMD friendliness. */
inline void axpy(double alpha, std::vector<double> const& x,
                 std::vector<double> const& y, std::vector<double> &z)
{
    // Guarantee the three vectors have the same size
    const std::size_t n = x.size();
    if (y.size() != n || z.size() != n) {
        throw std::runtime_error("Vector size mismatch in axpy");
    }

    // Parallel loop with static scheduling to distribute work evenly
    // Unroll factor 4 to encourage SIMD vectorisation
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i + 3 < n; i += 4) {
        z[i]     = alpha * x[i]     + y[i];
        z[i + 1] = alpha * x[i + 1] + y[i + 1];
        z[i + 2] = alpha * x[i + 2] + y[i + 2];
        z[i + 3] = alpha * x[i + 3] + y[i + 3];
    }
    // Handle the remainder (0 to 3 elements)
    for (std::size_t i = (n / 4) * 4; i < n; ++i) {
        z[i] = alpha * x[i] + y[i];
    }
}
