/**
 * Count the number of doubles in the vector `x` that have a fractional part
 * in the ranges:
 *   [0, 0.25)  -> bins[0]
 *   [0.25, 0.5) -> bins[1]
 *   [0.5, 0.75) -> bins[2]
 *   [0.75, 1)   -> bins[3]
 *
 * The function preserves the exact semantics of the original implementation
 * but is heavily optimised for speed:
 *   • OpenMP parallelism with a per‑thread private bin array.
 *   • Avoids expensive `floor`/`modf` calls; uses simple truncation
 *     and integer arithmetic to determine the quartile.
 *   • Uses a single pass over the data with minimal branching.
 */
inline void countQuartiles(const std::vector<double>& x, std::array<std::size_t, 4>& bins)
{
    // Initialise the output bins to zero.
    for (std::size_t i = 0; i < 4; ++i) bins[i] = 0;

    const std::size_t n = x.size();

    // Parallel accumulation: each thread writes to its own local bins.
    // The `reduction` clause accumulates into `bins` at the end.
#pragma omp parallel default(none) \
             shared(x, bins, n)     \
             private()              \
             reduction(+:bins[0]:bins[1]:bins[2]:bins[3])
    {
        // Local bin counters for this thread.
        std::size_t localBins[4] = {0, 0, 0, 0};

#pragma omp for schedule(static)
        for (std::size_t idx = 0; idx < n; ++idx) {
            const double val = x[idx];

            // Compute the fractional part using truncation toward zero.
            const double frac = val - static_cast<double>(static_cast<long long>(val));

            // Convert the fractional part to an integer in [0,4)
            // Subtract a tiny epsilon to protect against rounding errors
            // that could push a value like 0.7500000000000001 into the
            // next bucket.  The epsilon is smaller than any difference
            // that can arise from the limited precision of double.
            const int q = static_cast<int>((frac - 1e-16) * 4.0);

            if (q < 0) {
                // For negative values the original code uses the truncate‐toward‑zero
                // fraction, so we emulate the same behaviour – all negative fractions
                // fall into bin 0 (since -0.999... < 0.25).
                localBins[0] += 1;
            } else if (q < 4) {
                localBins[q] += 1;
            } else {
                // In the rare case that rounding pushes a value
                // exactly 1.0 into the 4th bucket, treat it as bin 3.
                localBins[3] += 1;
            }
        }

        // Merge local counters into the global result.
#pragma omp atomic
        for (int i = 0; i < 4; ++i) bins[i] += localBins[i];
    }
}
