#include <cstdint>

struct Point
{
    double x, y;
};

static inline double dist2(const Point &a, const Point &b)
{
    const double dx = a.x - b.x;
    const double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

static inline double cross(const Point &a, const Point &b, const Point &c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Return the perimeter of the smallest convex polygon that contains
   all the points in the vector points. */
double convexHullPerimeter(const std::vector<Point> &points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // copy & sort points
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point &a, const Point &b)
              { return a.x < b.x || (a.x == b.x && a.y < b.y); });

    // build convex hull (Monotone chain)
    std::vector<Point> hull;
    hull.reserve(n * 2);

    // lower hull
    for (const auto &pt : sorted)
    {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull.back(), pt) <= 0)
            hull.pop_back();
        hull.push_back(pt);
    }

    // upper hull
    size_t lower_size = hull.size();
    for (auto it = sorted.rbegin() + 1; it != sorted.rend(); ++it)
    {
        while (hull.size() >= lower_size + 1 &&
               cross(hull[hull.size() - 2], hull.back(), *it) <= 0)
            hull.pop_back();
        hull.push_back(*it);
    }

    // last point is same as first one; remove it
    hull.pop_back();

    // compute perimeter
    double perim = 0.0;
    for (size_t i = 0; i < hull.size(); ++i)
        perim += std::sqrt(dist2(hull[i], hull[(i + 1) % hull.size()]));
    return perim;
}
