#pragma once
#include <vector>
#include <omp.h>

/* Compute the reverse prefix sum of the vector x into output.
   Examples:
   input: [1, 7, 4, 6, 6, 2]
   output: [2, 8, 14, 18, 25, 26]
   input: [3, 3, 7, 1, -2]
   output: [-2, -1, 6, 9, 12]
*/
void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    const int thread_count = omp_get_max_threads();
    std::vector<int> partial_sums(thread_count + 1, 0);

    const std::size_t chunk = (n + thread_count - 1) / thread_count;

    /* Each thread computes a partial reverse scan on its segment
       and records the sum of its segment in partial_sums. */
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        int sum = 0;
        for (std::size_t i = end; i > start; --i) {
            sum += x[i - 1];
            output[i - 1] = sum;
        }
        partial_sums[tid + 1] = sum;
    }

    /* Adjust each segment by the sum of previous segments. */
    int cumulative = 0;
    for (int tid = 0; tid < thread_count; ++tid) {
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        if (start >= n) break;

        const int add = cumulative;
        cumulative += partial_sums[tid + 1];

        for (std::size_t i = start; i < end; ++i) {
            output[i] += add;
        }
    }
}
