struct Point {
    double x, y;
};

/*  Convex Hull using the monotone chain algorithm.  */
inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline bool pointLess(const Point& a, const Point& b) {
    return a.x < b.x || (a.x == b.x && a.y < b.y);
}

/*  Find the convex hull of 'points' and store it in 'hull'.
    The resulting hull will contain the vertices in counter‑clockwise order.
 */
void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    const std::size_t n = points.size();
    if (n < 3) {               // fewer than 3 points – the hull is the set itself
        hull = points;
        return;
    }

    // Copy and sort the points (lexicographically by x, then y)
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(), pointLess);

    // Preallocate space for the upper and lower hulls
    std::vector<Point> hullTmp(2 * n);
    std::size_t k = 0;          // current size of hullTmp

    /* Build lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hullTmp[k-2], hullTmp[k-1], pts[i]) <= 0)
            --k;
        hullTmp[k++] = pts[i];
    }

    /* Build upper hull */
    const std::size_t t = k + 1;   // start index for upper hull part
    for (std::size_t i = n-1; i > 0; --i) {
        while (k >= t && cross(hullTmp[k-2], hullTmp[k-1], pts[i-1]) <= 0)
            --k;
        hullTmp[k++] = pts[i-1];
    }

    hullTmp.resize(k-1);   // remove duplicate starting point
    hull.swap(hullTmp);    // efficient move into output
}
