inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 std::size_t M, std::size_t N)
{
    // Disallow zero‑sized arguments – a no‑op is safe and preserves behaviour.
    if (M == 0 || N == 0) return;

    // Use raw pointers for efficiency.
    const double* a = A.data();
    const double* vec = x.data();
    double* res  = y.data();

    // Decide on a reasonable inner‑loop block size for cache friendliness.
    constexpr std::size_t BLOCK = 64;   // Tuned for typical L1/L2 cache line sizes.

    // Parallelise the outer loop over rows.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        const std::size_t row_start = i * N;
        double       sum = 0.0;

        // Unroll the inner loop and use SIMD hints.
        std::size_t j = 0;
        for (; j + BLOCK <= N; j += BLOCK) {
            // Block of BLOCK elements.
            #pragma omp simd reduction(+:sum)
            for (std::size_t k = 0; k < BLOCK; ++k) {
                sum += a[row_start + j + k] * vec[j + k];
            }
        }
        // Remaining tail.
        for (; j < N; ++j) {
            sum += a[row_start + j] * vec[j];
        }

        res[i] = sum;
    }
}
