#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

// Euclidean distance (avoids unnecessary pow/sqrt)
inline double sqDist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx*dx + dy*dy;
}

double closestPair(std::vector<Point> const& points)
{
    const size_t n = points.size();
    if (n < 2) return 0.0;

    // Copy and sort by x
    std::vector<Point> pts(points.begin(), points.end());
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    // Auxiliary buffer for merge step
    std::vector<Point> tmp(n);

    std::function<double(size_t,size_t)> solve = [&](size_t l, size_t r)->double
    {
        if (r - l <= 3) {                     // brute
            double best = std::numeric_limits<double>::max();
            for (size_t i = l; i < r; ++i)
                for (size_t j = i+1; j < r; ++j)
                    best = std::min(best, sqDist(pts[i], pts[j]));
            // sort by y for outside call
            std::sort(pts.begin()+l, pts.begin()+r,
                      [](const Point& a, const Point& b){ return a.y < b.y; });
            return best;
        }
        size_t mid = l + (r-l)/2;
        double midx = pts[mid].x;
        double left = solve(l, mid);
        double right = solve(mid, r);
        double best = std::min(left, right);

        // merge by y into tmp
        std::merge(pts.begin()+l, pts.begin()+mid,
                   pts.begin()+mid, pts.begin()+r,
                   tmp.begin(), [](const Point& a, const Point& b){ return a.y < b.y; });
        std::copy(tmp.begin(), tmp.begin()+(r-l), pts.begin()+l);

        // strip
        std::vector<Point> strip;
        for (size_t i = l; i < r; ++i)
            if ((pts[i].x - midx)*(pts[i].x - midx) < best)
                strip.push_back(pts[i]);

        for (size_t i = 0; i < strip.size(); ++i)
            for (size_t j = i+1; j < strip.size() && (strip[j].y - strip[i].y)*(strip[j].y - strip[i].y) < best; ++j)
                best = std::min(best, sqDist(strip[i], strip[j]));
        return best;
    };

    // Parallelize the two halves of the initial call
    double left, right;
    #pragma omp parallel sections
    {
        #pragma omp section
        left = solve(0, n/2);
        #pragma omp section
        right = solve(n/2, n);
    }
    double minSq = std::min(left, right);
    return std::sqrt(minSq);
}
