#include <algorithm>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// ---------------------------------------------------------------------------
// Optimised radix‑2 iterative FFT (Cooley‑Tukey)
// ---------------------------------------------------------------------------

inline void fft(std::vector<std::complex<double>> const& in,
                std::vector<std::complex<double>> &out)
{
    const size_t N = in.size();
    if (N == 0) { out.clear(); return; }

    // Ensure N is a power of two
    if ((N & (N - 1)) != 0) {
        out = in; // fall‑back: no optimisation for non‑power‑of‑two
        return;
    }

    out.assign(in.begin(), in.end());          // copy input

    // Pre‑compute twiddle factors for each stage
    const size_t logN = static_cast<size_t>(std::log2(N));
    std::vector<std::vector<std::complex<double>>> twiddles(logN);

    double theta = -2.0 * M_PI / static_cast<double>(N);
    for (size_t s = 0; s < logN; ++s) {
        size_t m = 1ULL << (s + 1);
        twiddles[s].resize(m / 2);
        double step = theta * (m / 2);
        for (size_t k = 0; k < m / 2; ++k) {
            double w = step * k;
            twiddles[s][k] = std::complex<double>(std::cos(w), std::sin(w));
        }
    }

    // Bit‑reversal permutation
    for (size_t i = 0; i < N; ++i) {
        size_t rev = i;
        rev = ((rev & 0x55555555) << 1)  | ((rev & 0xaaaaaaaa) >> 1);
        rev = ((rev & 0x33333333) << 2)  | ((rev & 0xcccccccc) >> 2);
        rev = ((rev & 0x0f0f0f0f) << 4)  | ((rev & 0xf0f0f0f0) >> 4);
        rev = ((rev & 0x00ff00ff) << 8)  | ((rev & 0xff00ff00) >> 8);
        rev = (rev << 16) | (rev >> 16);
        rev >>= 32 - logN;

        if (rev > i) std::swap(out[i], out[rev]);
    }

    // Main FFT loop (radix‑2 butterflies)
    size_t stride = 1;                     // current stage stride
    for (size_t s = 0; s < logN; ++s, stride <<= 1) {
        const size_t half = stride;
        const size_t full = stride << 1;

        // Parallelise over outer loops when array large enough
        const size_t numThreads = std::thread::hardware_concurrency();
        const size_t block = (N / full + numThreads - 1) / numThreads;

        for (size_t t = 0; t < block; ++t) {
            const size_t start = t * block * full;
            const size_t end   = std::min(start + block * full, N);
            for (size_t i = start; i < end; i += full) {
                for (size_t j = 0; j < half; ++j) {
                    const size_t idx = i + j;
                    const std::complex<double> tmp = out[idx] - out[idx + half];
                    out[idx] += out[idx + half];
                    out[idx + half] = tmp * twiddles[s][j];
                }
            }
        }
    }
}
