/*
 * Compute the output grid where each cell is set to 1 iff *exactly one* of its
 * four (up, down, left, right) neighbours in the input grid is 1.  The
 * input and output grids are stored in row‑major order as flat vectors of
 * ints.  The original implementation uses simple bounds checks and a
 * nested for loop.  For speed we replace it with an OpenMP parallelized
 * version that operates on raw pointers, eliminates indirect accesses,
 * and removes the branching in the count logic.
 */
void cellsXOR(std::vector<int> const& input, std::vector<int> &output, size_t N)
{
    // Raw pointers for faster indexing
    const int* in  = input.data();
          int* out = output.data();
    const size_t stride = N;

    /* Parallelize the two nested loops with `collapse(2)` so that the
     * scheduling granularity is high enough for a large N while keeping
     * the thread‑consumption to a minimum.  Static scheduling works best
     * in a data‑parallel setting with predictable cache behaviour. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {

            // Load the neighbouring values; the check for equality to 1
            // is performed with a ternary that yields either 0 or 1,
            // thereby keeping the count as an integer without branching.
            int count = 0;
            if (i)                      count += (in[(i-1)*stride + j] == 1);
            if (i + 1 < N)              count += (in[(i+1)*stride + j] == 1);
            if (j)                      count += (in[i*stride + j-1] == 1);
            if (j + 1 < N)              count += (in[i*stride + j+1] == 1);

            out[i*stride + j] = (count == 1) ? 1 : 0;
        }
    }
}
