/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row-major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]
*/
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double>       &C,
                 std::size_t M,
                 std::size_t K,
                 std::size_t N)
{
    constexpr std::size_t BLOCK = 64;          // Tile size – tweak for cache
    const std::size_t lda = K;                 // stride of A
    const std::size_t ldb = N;                 // stride of B
    const std::size_t ldc = N;                 // stride of C

#   pragma omp parallel for schedule(static)
    for (std::size_t i0 = 0; i0 < M; i0 += BLOCK) {
        std::size_t imax = std::min(i0 + BLOCK, M);
        for (std::size_t k0 = 0; k0 < K; k0 += BLOCK) {
            std::size_t kmax = std::min(k0 + BLOCK, K);
            for (std::size_t j0 = 0; j0 < N; j0 += BLOCK) {
                std::size_t jmax = std::min(j0 + BLOCK, N);

                for (std::size_t i = i0; i < imax; ++i) {
                    double *c_row = &C[i * ldc + j0];
                    const double *a_row = &A[i * lda + k0];
                    for (std::size_t k = k0; k < kmax; ++k) {
                        double aik = a_row[k - k0];
                        const double *b_col = &B[k * ldb + j0];
                        for (std::size_t j = j0; j < jmax; ++j) {
                            c_row[j - j0] += aik * b_col[j - j0];
                        }
                    }
                }
            }
        }
    }
