/*
   Return the index of the value in the vector x that is closest to the math
   constant PI.  If multiple values are equally close, return the first such
   index.  The implementation is thread‑safe, does not change the observable
   behaviour and is optimized for a modern x86‑64 CPU with up to 8 threads.
*/
size_t findClosestToPi(std::vector<double> const& x) {
    size_t result_index = 0;
    double best_diff  = std::abs(x[0] - M_PI);

    // We use OpenMP to split the work among the available threads but keep
    // the “first occurrence” semantics by performing a local scan per thread
    // and then reducing in a critical section.
#pragma omp parallel
    {
        size_t local_idx = 0;
        double local_min = std::numeric_limits<double>::infinity();

        // Each thread scans a chunk of the vector
#pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i) {
            double diff = std::abs(x[i] - M_PI);
            if (diff < local_min) {
                local_min = diff;
                local_idx = i;
            }
        }

        // Combine the results of all threads
#pragma omp critical
        {
            if (local_min < best_diff) {
                best_diff   = local_min;
                result_index = local_idx;
            }
        }
    }

    return result_index;
}
