    if (imageOut.size() < N * N) imageOut.resize(N * N);

    // Parallelise the outer loops.  `collapse(2)` flattens the two loops
    // into a single 2‑D space for work distribution.
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        for (size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            // Handle the nine neighbours manually – this removes the
            // programmatic loop over k,l and lets the compiler unroll.
            const int base = static_cast<int>(i * N + j);

            // (i‑1, j‑1)
            if (i > 0 && j > 0) sum += imageIn[(i - 1) * N + (j - 1)] * edgeKernel[0][0];
            // (i‑1, j)
            if (i > 0)           sum += imageIn[(i - 1) * N +  j    ] * edgeKernel[0][1];
            // (i‑1, j+1)
            if (i > 0 && j + 1 < N) sum += imageIn[(i - 1) * N + (j + 1)] * edgeKernel[0][2];
            // (i,   j‑1)
            if (j > 0)           sum += imageIn[ i     * N + (j - 1)] * edgeKernel[1][0];
            // (i,   j)
            sum += imageIn[base] * edgeKernel[1][1];
            // (i,   j+1)
            if (j + 1 < N)       sum += imageIn[ i     * N + (j + 1)] * edgeKernel[1][2];
            // (i+1, j‑1)
            if (i + 1 < N && j > 0) sum += imageIn[(i + 1) * N + (j - 1)] * edgeKernel[2][0];
            // (i+1, j)
            if (i + 1 < N)         sum += imageIn[(i + 1) * N +  j    ] * edgeKernel[2][1];
            // (i+1, j+1)
            if (i + 1 < N && j + 1 < N) sum += imageIn[(i + 1) * N + (j + 1)] * edgeKernel[2][2];

            // Clamp to [0,255]
            imageOut[base] = static_cast<int>(std::min(std::max(sum, 0), 255));
        }
    }
}
