#pragma once
#include <vector>
#include <algorithm>

/* Return true if `val` is present in exactly one of vectors x or y.
   Duplicates are ignored (the search is case‑insensitive to multiplicity).
   Optimised for large inputs: copy, sort and binary_search on the smaller set
   to achieve better asymptotic complexity than repeated linear scans.
*/
bool xorContains(std::vector<int> const& x, std::vector<int> const& y, int val) {
    // Work on copies so we can sort without modifying the input
    std::vector<int> xs = x;
    std::vector<int> ys = y;

    // Sort both vectors once; this is O(nlogn) and usually faster than many linear scans
    std::sort(xs.begin(), xs.end());
    std::sort(ys.begin(), ys.end());

    // Binary search is O(log n); quick and cache‑friendly
    bool foundInX = std::binary_search(xs.begin(), xs.end(), val);
    bool foundInY = std::binary_search(ys.begin(), ys.end(), val);

    // XOR of the two boolean results gives the final answer
    return foundInX ^ foundInY;
}
