#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:
   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
   The routine uses Gaussian elimination with partial pivoting and
   OpenMP parallelisation on the inner elimination loops.
*/
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              size_t N)
{
    // Work copies – the vector layouts are unchanged
    std::vector<double> Acopy(A);
    std::vector<double> bcopy(b);
    x.assign(N, 0.0);                     // initialise output

    double* Aptr = Acopy.data();
    double* bptr = bcopy.data();
    double* xptr = x.data();

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N - 1; ++i) {
        // Determine pivot row
        size_t pivot_row = i;
        double max_val = std::abs(Aptr[i * N + i]);
        for (size_t r = i + 1; r < N; ++r) {
            double val = std::abs(Aptr[r * N + i]);
            if (val > max_val) { max_val = val; pivot_row = r; }
        }

        // Zero pivot => singular – keep original behaviour (do nothing)
        if (max_val == 0.0) return;

        // Swap pivot row with current row if needed
        if (pivot_row != i) {
            std::swap_ranges(Aptr + i * N, Aptr + (i + 1) * N, Aptr + pivot_row * N);
            std::swap(bptr[i], bptr[pivot_row]);
        }

        double pivot = Aptr[i * N + i];

        // Eliminate rows below
        #pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            double factor = Aptr[j * N + i] / pivot;
            double* rowj = Aptr + j * N;
            double* rowi = Aptr + i * N;
            for (size_t k = i; k < N; ++k)
                rowj[k] -= factor * rowi[k];
            bptr[j] -= factor * bptr[i];
        }
    }

    // Back substitution – executed serially (cost negligible)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        double* row = Aptr + i * N;
        for (size_t j = i + 1; j < N; ++j)
            sum += row[j] * xptr[j];
        xptr[i] = (bptr[i] - sum) / row[i];
    }
}
