#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Parallel 5‑point 2D Jacobi stencil
 *
 *   output[i,j] = (input[i-1,j] + input[i+1,j] + input[i,j-1] + input[i,j+1] + input[i,j]) / 5
 *   Values outside the grid are treated as 0.
 *
 *  The implementation splits the work into three contiguous regions:
 *    1) interior cells (i=1..N-2, j=1..N-2) – no bounds checks needed
 *    2) first and last rows – need only vertical neighbours
 *    3) first and last columns – need only horizontal neighbours
 *
 *  All loops are parallelised with OpenMP; each worker processes a contiguous
 *  chunk of elements with pointer increments for maximum cache efficiency.
 *
 *  Exact behaviour matches the original scalar code.
 */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double> &output,
                     const size_t N) noexcept
{
    const double inv5 = 0.2;          // 1/5
    const size_t stride = N;          // row stride

    /* ------------------------------------------------------------------ *
     * 1) Interior: all neighbours are valid – no branch penalties        *
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i + 1 < N; ++i) {
        const double* row_up   = &input[(i - 1) * stride];
        const double* row_mid  = &input[i     * stride];
        const double* row_low  = &input[(i + 1) * stride];
        double* out = &output[i * stride + 1];

        for (size_t j = 1; j + 1 < N; ++j) {
            *out++ = (row_up[j] + row_low[j] + row_mid[j-1] + row_mid[j+1] + row_mid[j]) * inv5;
        }
    }

    /* ------------------------------------------------------------------ *
     * 2) Top and bottom rows – missing vertical neighbours                *
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (size_t i : {0, N-1}) {
        const double* row      = &input[i * stride];
        double* out           = &output[i * stride];

        /* first element (corner) */
        out[0] = (row[1] + row[0]) * inv5;           // left/right + self

        /* interior columns */
        for (size_t j = 1; j + 1 < N; ++j) {
            out[j] = (row[j-1] + row[j+1] + row[j]) * inv5;
        }

        /* last element (corner) */
        out[N-1] = (row[N-2] + row[N-1]) * inv5;
    }

    /* ------------------------------------------------------------------ *
     * 3) Left and right columns – missing horizontal neighbours          *
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i + 1 < N; ++i) {
        const double* row = &input[i * stride];
        double* out = &output[i * stride];

        /* first column (left edge) */
        out[0] = (row[1] + row[0] + row[stride]) * inv5;   // up/down + self

        /* interior rows */
        for (size_t j = 1; j + 1 < N; ++j) {
            out[j] = (row[j-1] + row[j+1] + row[j] + row[j+stride] + row[j - stride]) * inv5;
        }

        /* last column (right edge) */
        out[N-1] = (row[N-2] + row[N-1] + row[N-1 + stride]) * inv5;
    }
}
