#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
   High‑performance LU factorisation (Doolittle) for a square N×N matrix.
   The matrix is stored row‑major in a 1‑dimensional vector A.
   Sub‑matrices are processed using a simple cache‑friendly blocking scheme.
   For each pivot column k, the rows k+1 … N‑1 are updated in parallel.
   A is overwritten with the L (unit diagonal omitted) and U factors.
*/
template <size_t BLOCK = 64>
void luFactorize(std::vector<double>& A, std::size_t N)
{
    const std::size_t n = N;
    // Main outer loop – blocked on rows/columns for better locality
    for (std::size_t kb = 0; kb < n; kb += BLOCK) {
        const std::size_t klim = std::min(n, kb + BLOCK);

        /* --------------------------------------------
           1. Update the pivot block A[kb:klim-1][kb:klim-1]
               (no parallelisation; small enough to fit in L1)
        -------------------------------------------- */
        for (std::size_t k = kb; k < klim; ++k) {
            double pivot = A[k * n + k];
            for (std::size_t i = k + 1; i < klim; ++i) {
                double factor = A[i * n + k] / pivot;
                A[i * n + k] = factor;          // store L factor
                for (std::size_t j = k + 1; j < klim; ++j) {
                    A[i * n + j] -= factor * A[k * n + j];
                }
            }
        }

        /* --------------------------------------------
           2. Divide the remaining matrix into sub‑blocks.
              For each block below the pivot (rows > klim)
              we compute the L‑values and update the corresponding
              block of U elements.  Each row of this sub‑block is
              independent, so we parallelise over rows using OpenMP.
        -------------------------------------------- */
        if (klim == n) continue;   // finished

        #pragma omp parallel for schedule(static, 1)
        for (std::size_t ib = klim; ib < n; ib += BLOCK) {
            const std::size_t iend = std::min(n, ib + BLOCK);
            for (std::size_t jb = klim; jb < n; jb += BLOCK) {
                const std::size_t jend = std::min(n, jb + BLOCK);

                // Process the (ib: iend-1) × (jb: jend-1) block
                for (std::size_t i = ib; i < iend; ++i) {
                    double factor = A[i * n + kb];    // _kp = left part of row i
                    for (std::size_t j = kb; j < klim; ++j)
                        factor -= A[i * n + j] * A[j * n + kb];
                    factor /= A[kb * n + kb];
                    A[i * n + kb] = factor;           // store L factor

                    // Update the remainder of the row i
                    for (std::size_t j = jb; j < jend; ++j) {
                        double sum = 0.0;
                        for (std::size_t l = kb; l < klim; ++l)
                            sum += A[i * n + l] * A[l * n + j];
                        A[i * n + j] -= sum;
                    }
                }
            }
        }
    }
}
