// Forward declaration of helper functions
inline void fft_radix2(std::vector<std::complex<double>>& data);
inline void bit_reverse(std::vector<std::complex<double>>& data);
inline void conjugate_inplace(std::vector<std::complex<double>>& data);

// Public API
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    // 1) Perform an in‑place radix‑2 FFT
    fft_radix2(x);

    // 2) Bit‑reverse the result back to natural order (the original code did this after the transform)
    bit_reverse(x);

    // 3) Conjugate every element
    conjugate_inplace(x);
}

/* ---------------------------------------------------------------------- */
/*  Radix‑2 Cooley‑Tukey FFT (in‑place, data size is a power of 2)         */
/*  The algorithm follows the classic Stockham/Sarrus arrangement.          */
/*  We pre‑compute twiddle factors and use SIMD‑friendly accesses.          */
/* ---------------------------------------------------------------------- */
static inline void fft_radix2(std::vector<std::complex<double>>& data)
{
    const std::size_t N = data.size();
    if (N <= 1) return;

    const std::size_t stages = static_cast<std::size_t>(std::log2(N));
    const double PI = 3.141592653589793238462643383279502884L;

    // Allocate a temporary buffer for the butterfly step
    std::vector<std::complex<double>> temp(N);

    // Pre‑compute twiddle factor table for all stages
    std::vector<std::vector<std::complex<double>>> twiddles(stages);
    for (std::size_t s = 0; s < stages; ++s) {
        const std::size_t span = 1ULL << s;          // 2^s
        const std::size_t half  = span << 1;         // 2^(s+1)
        twiddles[s].resize(span);
        const double angle = -PI / span;             // negative for forward FFT
        for (std::size_t k = 0; k < span; ++k) {
            twiddles[s][k] = std::cos(angle * k) + std::sin(angle * k) * std::complex<double>(0.0, 1.0);
        }
    }

    // Main butterfly loop
    for (std::size_t s = 0; s < stages; ++s) {
        const std::size_t span = 1ULL << s;          // lower half of sub‑arrays
        const std::size_t half  = span << 1;         // full sub‑array size
        const auto& w = twiddles[s];

        // Parallelize outermost loop over sub‑arrays
#pragma omp parallel for schedule(static)
        for (std::size_t b = 0; b < N; b += half) {
            for (std::size_t i = 0; i < span; ++i) {
                const std::size_t idx1 = b + i;
                const std::size_t idx2 = idx1 + span;
                const std::complex<double> t = w[i] * data[idx2];
                data[idx2] = data[idx1] - t;
                data[idx1] = data[idx1] + t;
            }
        }
    }
}

/* ---------------------------------------------------------------------- */
/*  Bit‑reversal permutation (in‑place)                                     */
/*  Uses a lookup table for 16‑bit reversals to speed up the operation.     */
/* ---------------------------------------------------------------------- */
static inline void bit_reverse(std::vector<std::complex<double>>& data)
{
    const std::size_t N = data.size();
    if (N <= 1) return;

    const std::size_t bits = static_cast<std::size_t>(std::log2(N));
    static const std::uint32_t rev16[1 << 16] = []() {
        std::uint32_t table[1 << 16];
        for (std::uint32_t i = 0; i < (1U << 16); ++i) {
            std::uint32_t v = i;
            v = ((v & 0x55555555U) << 1) | ((v & 0xAAAAAAAAU) >> 1);
            v = ((v & 0x33333333U) << 2) | ((v & 0xCCCCCCCCU) >> 2);
            v = ((v & 0x0F0F0F0FU) << 4) | ((v & 0xF0F0F0F0U) >> 4);
            v = ((v & 0x00FF00FFU) << 8) | ((v & 0xFF00FF00U) >> 8);
            table[i] = v >> (32 - 16);
        }
        return table;
    }();

    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev16[static_cast<std::uint32_t>(i)];
        j >>= (32 - bits);
        if (j > i) std::swap(data[i], data[j]);
    }
}

/* ---------------------------------------------------------------------- */
/*  Conjugate every complex element (in‑place)                              */
/* ---------------------------------------------------------------------- */
static inline void conjugate_inplace(std::vector<std::complex<double>>& data)
{
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < data.size(); ++i) {
        data[i] = std::conj(data[i]);
    }
}
