#pragma once
#include <cmath>
#include <vector>
#include <complex>
#include <algorithm>
#include <cstdint>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
// In‑place radix‑2 Cooley‑Tukey FFT (forward or inverse via conjugation)
// -----------------------------------------------------------------------------
inline void fft_inplace(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // ----------------------------------------------------------
    // Pre‑compute the (conjugated) twiddle factors for each stage
    // ----------------------------------------------------------
    std::size_t stages = 0;
    std::size_t n_tmp = N;
    while (n_tmp >>= 1) ++stages;                // log2(N)
    std::vector<std::vector<std::complex<double>>> twiddles(stages);

    for (std::size_t s = 0; s < stages; ++s) {
        const std::size_t m = 1ULL << s;                 // current sub‑transform size
        const std::size_t m2 = m << 1;
        twiddles[s].resize(m);
        const double theta = -2.0 * M_PI / (double)m2;  // negative for inverse
        double w_real = std::cos(theta);
        double w_imag = std::sin(theta);                // sin, sin(−theta) = −sin(theta)
        for (std::size_t k = 0; k < m; ++k) {
            twiddles[s][k] = std::complex<double>(w_real, w_imag);
            // rotate one step for next factor
            const double temp = w_real;
            w_real = w_real * twiddles[s][0].real() - w_imag * twiddles[s][0].imag();
            w_imag = temp * twiddles[s][0].imag() + w_imag * twiddles[s][0].real();
        }
    }

    // ----------------------------------------------------------
    // Cooley‑Tukey butterfly stages
    // ----------------------------------------------------------
    for (std::size_t s = 0; s < stages; ++s) {
        const std::size_t m = 1ULL << s;
        const std::size_t m2 = m << 1;
        const auto &W = twiddles[s];

        #pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < m; ++j) {
            std::complex<double> w = W[j];
            for (std::size_t i = j; i < N; i += m2) {   // point‑to‑point butterfly
                std::complex<double> u = x[i];
                std::complex<double> t = w * x[i + m];
                x[i] = u + t;
                x[i + m] = u - t;
            }
        }
    }

    // ----------------------------------------------------------
    // Bit‑reversal reordering
    // ----------------------------------------------------------
    // use 32‑bit scramble for 64‑bit indices (works for N <= 2^32)
    const std::size_t logN = stages;
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        j = ((j & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((j & 0x5555555555555555ULL) << 1);
        j = ((j & 0xccccccccccccccccULL) >> 2) | ((j & 0x3333333333333333ULL) << 2);
        j = ((j & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((j & 0x0f0f0f0f0f0f0f0fULL) << 4);
        j = ((j & 0xff00ff00ff00ff00ULL) >> 8) | ((j & 0x00ff00ff00ff00ffULL) << 8);
        j = ((j & 0xffff0000ffff0000ULL) >> 16) | ((j & 0x0000ffff0000ffffULL) << 16);
        j = ((j & 0xffffffff00000000ULL) >> 32) | ((j & 0x00000000ffffffffULL) << 32);
        j >>= (64 - logN);
        if (j > i) std::swap(x[i], x[j]);
    }
}

// -----------------------------------------------------------------------------
// Inverse FFT (conjugate‑method)
// -----------------------------------------------------------------------------
static inline void fft_inverse(std::vector<std::complex<double>> &x)
{
    // Conjugate, forward FFT, conjugate again
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v) { return std::conj(v); });

    fft_inplace(x);

    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v) { return std::conj(v); });

    // Normalize by 1/N
    const double invN = 1.0 / static_cast<double>(x.size());
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] *= invN;
}
