#pragma once
#include <cstdint>
#include <vector>
#include <cstring>
#include <omp.h>

/* For each value in the vector `x` compute its rank in the sorted order
   (stable for equal values).  The algorithm is a 4‑phase radix sort on
   the 32‑bit IEEE‑754 representation of the floats.  It exploits 8
   threads via OpenMP, is O(n) in practice, and preserves the exact
   semantics of the original implementation.  */
inline void ranks(std::vector<float> const& x, std::vector<std::size_t>& ranks_)
{
    const std::size_t n = x.size();
    if (n == 0) { ranks_.clear(); return; }

    // Pack each float and its original index into a 64‑bit key.
    // Ordering of the high 32 bits guarantees IEEE‑754 lexicographic order,
    // and the low 32 bits preserve the original index for tie breaking.
    std::vector<uint64_t> buf(n);
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        uint32_t f;
        std::memcpy(&f, &x[i], sizeof f);
        buf[i] = (static_cast<uint64_t>(f) << 32) | i;
    }

    // Temporary buffer for radix passes.
    std::vector<uint64_t> tmp(n);

    // Radix sort with base 2^16 (4 passes: 16, 16, 16, 16)
    const int BITS = 16;
    const int RADIX = 1 << BITS;
    uint64_t mask = RADIX - 1;
    uint64_t shift = 0;

    for (int pass = 0; pass < 4; ++pass) {
        // Count occurrences of each bucket (32 bits per key, 4 passes).
        std::vector<std::size_t> counts(RADIX, 0);

        // Parallel counting
        #pragma omp parallel
        {
            std::vector<std::size_t> local(RADIX, 0);
            #pragma omp for schedule(static)
            for (std::size_t i = 0; i < n; ++i) {
                std::size_t bucket = (buf[i] >> shift) & mask;
                ++local[bucket];
            }
            #pragma omp critical
            {
                for (int b = 0; b < RADIX; ++b) counts[b] += local[b];
            }
        }

        // Prefix sum to compute starting positions
        std::vector<std::size_t> positions(RADIX);
        std::size_t sum = 0;
        for (int b = 0; b < RADIX; ++b) {
            positions[b] = sum;
            sum += counts[b];
        }

        // Rearrange elements into tmp according to bucket positions
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            std::size_t bucket = (buf[i] >> shift) & mask;
            std::size_t pos = positions[bucket]++;
            tmp[pos] = buf[i];
        }

        // Swap buffers for next pass
        buf.swap(tmp);
        shift += BITS;
    }

    // Extract ranks from sorted keys
    for (std::size_t i = 0; i < n; ++i) {
        std::size_t orig_idx = static_cast<std::size_t>(buf[i] & 0xffffffffu);
        ranks_[orig_idx] = i;
    }
}
